  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">El Multiplicador de Flujo de Dinero (MFM): la posición del cierre determina el signo</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">MFM = [(Cierre-Mínimo) - (Máximo-Cierre)] / (Máximo-Mínimo)</text>
    <line x1="150" y1="90" x2="150" y2="250" stroke="#71717a" stroke-width="4"/>
    <line x1="130" y1="90" x2="170" y2="90" stroke="#4ade80" stroke-width="6"/>
    <text x="180" y="94" fill="#71717a" font-size="13" font-family="sans-serif">Máximo</text>
    <text x="180" y="254" fill="#71717a" font-size="13" font-family="sans-serif">Mínimo</text>
